{% extends "_base/base.html.j2" %}
{% set SHOW_PRICES = (data.showPrices | default(true)) %}

{% set buyer   = data.documentAddress | default({}) %}
{% set sold    = ((data.effectiveAddresses or {}).soldTo) | default(buyer) %}
{% set ship    = ((data.effectiveAddresses or {}).shipTo) | default({}) %}
{% set items   = data.lineItems | default([]) %}
{% set contact = data.contactPerson | default({}) %}
{% set comp    = data.company | default({}) %}
{% set pay     = data.payment | default({}) %}
{% set terms   = data.financials.paymentTerms.paymentTargetDays %}

{% set _ship_differs = ship and ship.name and ((ship.street or '') != (sold.street or '') or (ship.zipCode or '') != (sold.zipCode or '') or (ship.name or '') != (sold.name or '')) %}

{%- macro eur(v) -%}
{%- set cents = ((v | float) * 100 + 0.5) | int -%}
{%- set euros = (cents // 100) -%}
{%- set rem = cents - euros * 100 -%}
{%- set digits = euros | string -%}
{%- set n = digits | length -%}
{%- set ns = namespace(out='') -%}
{%- for i in range(n) -%}
{%- if i > 0 and (n - i) % 3 == 0 -%}{%- set ns.out = ns.out ~ '.' -%}{%- endif -%}
{%- set ns.out = ns.out ~ digits[i] -%}
{%- endfor -%}
{{ ns.out }},{{ '%02d' | format(rem) }}
{%- endmacro -%}

{% block title %}{{ L.doc_title }} {{ data.documentNumber }}{% endblock %}

{% block content %}
<div class="bl-doc">
  <table class="bl-foot"><tr>
    <td class="bl-foot-col">{{ comp.name }}<br>{{ comp.street | default(comp.address) }}<br>{% if comp.zipCity %}{{ comp.zipCity }}{% endif %}</td>
    <td class="bl-foot-col">{% if comp.vatId %}{{ L.vat_id_label }} {{ comp.vatId }}<br>{% endif %}{% if comp.hrb %}HRB {{ comp.hrb }}<br>{% endif %}{% if comp.phone %}Telefon {{ comp.phone }}{% endif %}</td>
    <td class="bl-foot-col">{% if comp.ceo %}{{ L.ceo_title }}:<br>{{ comp.ceo }}<br>{% endif %}E-Mail: {{ comp.email | default('') }}</td>
  </tr></table>

  <header class="bl-top">
    {% if assets.logo %}<img src="{{ assets.logo }}" alt="{{ comp.name }}" class="bl-logo">{% endif %}
  </header>
  <p class="bl-sender">{{ comp.name }}{% if comp.address %}, {{ comp.address }}{% endif %}</p>
  <address class="bl-recipient">{{ buyer.name }}<br>{% if buyer.coName %}{{ buyer.coName }}<br>{% endif %}{{ buyer.street }}<br>{{ buyer.zipCode }} {{ buyer.city }}</address>
  <div class="bl-subject-row">
    <h1 class="bl-subject">{{ L.doc_title }} {{ data.documentNumber }}</h1>
    <table class="bl-info"><tbody>
      {% if data.customerNumber %}<tr><th scope="row">{{ L.customer_number }}:</th><td>{{ data.customerNumber }}</td></tr>{% endif %}
      {% if data.documentDate %}<tr><th scope="row">{{ L.invoice_date }}:</th><td>{{ data.documentDate | date }}</td></tr>{% endif %}
      {% if data.deliveryDate %}<tr><th scope="row">{{ L.service_date }}:</th><td>{{ data.deliveryDate | date }}</td></tr>{% endif %}
      {% if data.customerOrderNumber %}<tr><th scope="row">{{ L.order_ref }}:</th><td>{{ data.customerOrderNumber }}</td></tr>{% endif %}
      {% if contact.name %}<tr><th scope="row">{{ L.processor }}:</th><td>{{ contact.name }}</td></tr>{% endif %}
      {% if comp.email %}<tr><th scope="row">E-Mail:</th><td>{{ comp.email }}</td></tr>{% endif %}
    </tbody></table>
  </div>
  <div class="bl-intro"><p>{{ L.salutation }}</p><p>{{ L.thank_you }}</p></div>
  {% if SHOW_PRICES %}<table class="bl-items">
    <colgroup><col class="c-pos"><col class="c-artno"><col class="c-art"><col class="c-qty"><col class="c-vat"><col class="c-unit"><col class="c-total"></colgroup>
    <thead><tr><th scope="col">{{ L.col_pos }}</th><th scope="col">{{ L.col_artno }}</th><th scope="col">{{ L.col_article }}</th><th scope="col" class="num">{{ L.col_qty }}</th><th scope="col" class="num">{{ L.col_vat }}</th><th scope="col" class="num">{{ L.col_unit_price }}</th><th scope="col" class="num">{{ L.col_total }}</th></tr></thead>
    <tbody>
      {% set pos = namespace(n=0) %}
      {% for li in items %}
        {% if li.type == 'heading' %}<tr class="bl-row-heading"><td></td><td></td><td colspan="5">{{ li.name }}</td></tr>
        {% elif li.type in ['subtotal', 'group_total'] %}<tr class="bl-row-sub"><td colspan="6">{{ li.name }}</td><td class="num">{% if li.lineItemRevenue %}{{ eur(li.lineItemRevenue.gross.amount if (li.lineItemRevenue.gross and li.lineItemRevenue.gross.amount) else li.lineItemRevenue.net.amount) }}{% endif %}</td></tr>
        {% elif li.type == 'page_break' %}<tr><td colspan="7"></td></tr>
        {% else %}{% set pos.n = pos.n + 1 %}<tr><td>{{ pos.n }}</td><td>{{ li.number }}</td><td><span class="art-name{% if li.price %} is-main{% endif %}">{{ li.name }}</span>{% if li.description %}<br><span class="art-desc">{{ li.description }}</span>{% endif %}</td><td class="num">{{ li.quantity }}{% if li.unit %} {{ li.unit }}{% endif %}</td><td class="num">{% if li.price %}{{ li.effectiveTaxRate }}%{% endif %}</td><td class="num">{% if li.price %}{{ eur(li.price.gross.amount if (li.price.gross and li.price.gross.amount) else li.price.net.amount) }}{% endif %}</td><td class="num">{% if li.lineItemRevenue %}{{ eur(li.lineItemRevenue.gross.amount if (li.lineItemRevenue.gross and li.lineItemRevenue.gross.amount) else li.lineItemRevenue.net.amount) }}{% endif %}</td></tr>{% endif %}
      {% endfor %}
    </tbody>
  </table>{% else %}<table class="bl-items">
    <colgroup><col class="c-pos"><col class="c-artno"><col class="c-art"><col class="c-qty"></colgroup>
    <thead><tr><th scope="col">{{ L.col_pos }}</th><th scope="col">{{ L.col_artno }}</th><th scope="col">{{ L.col_article }}</th><th scope="col" class="num">{{ L.col_qty }}</th></tr></thead>
    <tbody>
      {% set pos = namespace(n=0) %}
      {% for li in items %}
        {% if li.type == 'heading' %}<tr class="bl-row-heading"><td></td><td></td><td colspan="2">{{ li.name }}</td></tr>
        {% else %}{% set pos.n = pos.n + 1 %}<tr><td>{{ pos.n }}</td><td>{{ li.number }}</td><td><span class="art-name is-main">{{ li.name }}</span>{% if li.description %}<br><span class="art-desc">{{ li.description }}</span>{% endif %}</td><td class="num">{{ li.quantity }}{% if li.unit %} {{ li.unit }}{% endif %}</td></tr>{% endif %}
      {% endfor %}
    </tbody>
  </table>{% endif %}
  {% if SHOW_PRICES %}{% set net = (data.totals.net.amount | default('0')) | float %}
  {% set gross = (data.totals.gross.amount | default('0')) | float %}
  {% set vat = gross - net %}
  {% set rate = (data.financials.tax.taxRates.standard) | default(19) %}
  <table class="bl-totals"><tbody>
    <tr><th scope="row">{{ L.net_total }}</th><td class="num">{{ eur(net) }} EUR</td></tr>
    <tr><th scope="row">{{ L.vat_label }} {{ '%.2f' | format(rate | float) | replace('.', ',') }} %</th><td class="num">{{ eur(vat) }} EUR</td></tr>
    <tr class="bl-grand"><th scope="row">{{ L.gross_total }}</th><td class="num">{{ eur(gross) }} EUR</td></tr>
  </tbody></table>{% endif %}
  <div class="bl-shipto"><p class="bl-shipto__label">{{ L.ship_to }}:</p>{% if _ship_differs %}<address>{{ ship.name }}<br>{% if ship.coName %}{{ ship.coName }}<br>{% endif %}{{ ship.street }}<br>{{ ship.zipCode }} {{ ship.city }}</address>{% else %}<p>{{ L.ship_same }}</p>{% endif %}</div>
  {% if data.paymentNote or terms or pay.iban %}
  <div class="bl-pay">
    <p class="bl-pay__label">{{ L.pay_heading }}:</p>
    {% if data.paymentNote %}<p>{{ data.paymentNote }}</p>{% endif %}
    {% if terms %}<p>{{ L.pay_terms_pre }} {{ terms }} {{ L.pay_terms_post }}</p>{% endif %}
    {% if pay.iban %}<p>{{ L.pay_bank_intro }}</p>
    <table class="bl-bank"><tbody>{% if pay.bankName %}<tr><th scope="row">{{ L.bank }}</th><td>{{ pay.bankName }}</td></tr>{% endif %}<tr><th scope="row">{{ L.iban }}</th><td>{{ pay.iban }}</td></tr>{% if pay.bic %}<tr><th scope="row">{{ L.bic }}</th><td>{{ pay.bic }}</td></tr>{% endif %}</tbody></table>{% endif %}
  </div>
  {% endif %}
  <div class="bl-notes"><p>{{ L.machine_note }}</p></div>
</div>
{% endblock %}

css:
/* blanco draws its own header (.bl-top); suppress the base letterhead wrapper. */
.doc-header { display: none !important; }
@page {
  size: A4; margin: 16mm 20mm 25mm 25mm;
  @bottom-left { content: "Beispiel Handels GmbH · Marktplatz 1 · 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Beispiel"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; vertical-align: top; padding-top: 4mm; }
  @bottom-center { content: "Seite " counter(page) " von " counter(pages); font-size: 6.5pt; color: #8a8a8a; white-space: nowrap; vertical-align: top; padding-top: 4mm; }
  @bottom-right { content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A IBAN DE89 3704 0044 0532 0130 00 · BIC COBADEFFXXX"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm; }
}
.bl-doc { font-family: 'Helvetica', 'Arial', sans-serif; color: #111; font-size: 10pt; line-height: 1.4; }
.bl-foot { display: none; }
.bl-top { text-align: right; min-height: 16mm; }
.bl-logo { max-height: 14mm; width: auto; }
.bl-sender { font-size: 7pt; text-decoration: underline; margin: 10mm 0 5mm; color: #222; }
.bl-recipient { font-style: normal; font-size: 10.5pt; line-height: 1.45; margin: 0 0 12mm; }
.bl-subject-row { display: flex; justify-content: space-between; align-items: flex-start; gap: 10mm; margin-bottom: 6mm; }
.bl-subject { font-size: 12pt; font-weight: 700; margin: 0; white-space: nowrap; flex: 0 0 auto; }
.bl-info { border-collapse: collapse; font-size: 9.5pt; }
.bl-info th { font-weight: 400; text-align: left; padding: 0.3mm 6mm 0.3mm 0; white-space: nowrap; }
.bl-info td { text-align: left; white-space: nowrap; }
.bl-intro { margin: 0 0 6mm; line-height: 1.5; }
.bl-intro p { margin: 0 0 1.5mm; }
.bl-items { width: 100%; border-collapse: collapse; table-layout: fixed; font-size: 9pt; margin-bottom: 4mm; }
.bl-items col.c-pos { width: 9mm; } .bl-items col.c-artno { width: 20mm; } .bl-items col.c-qty { width: 14mm; } .bl-items col.c-vat { width: 13mm; } .bl-items col.c-unit { width: 22mm; } .bl-items col.c-total { width: 24mm; }
.bl-items thead th { border-bottom: 0.7pt solid #111; text-align: left; padding: 1.6mm 2mm; font-weight: 700; vertical-align: bottom; }
.bl-items tbody td { padding: 1.4mm 2mm; vertical-align: top; }
.bl-items tbody tr { page-break-inside: avoid; }
.bl-items thead { display: table-header-group; }
.bl-items .num { text-align: right; font-variant-numeric: tabular-nums; }
.art-name.is-main { font-weight: 700; } .art-desc { font-size: 8pt; color: #555; }
.bl-row-heading td { font-weight: 700; padding-top: 3mm; } .bl-row-sub td { font-weight: 700; border-top: 0.4pt solid #999; }
.bl-totals { margin: 0 0 0 auto; border-collapse: collapse; font-size: 9.5pt; min-width: 72mm; page-break-inside: avoid; }
.bl-totals th { font-weight: 400; text-align: left; padding: 0.8mm 8mm 0.8mm 0; white-space: nowrap; }
.bl-totals td { text-align: right; font-variant-numeric: tabular-nums; white-space: nowrap; }
.bl-totals .bl-grand th, .bl-totals .bl-grand td { font-weight: 700; border-top: 0.7pt solid #111; padding-top: 1.5mm; }
.bl-shipto { margin: 8mm 0 0; font-size: 9.5pt; } .bl-shipto__label { font-weight: 700; margin: 0 0 1mm; } .bl-shipto address { font-style: normal; line-height: 1.4; }
.bl-pay { margin: 6mm 0 0; font-size: 9.5pt; line-height: 1.5; } .bl-pay__label { font-weight: 700; margin: 0 0 1mm; } .bl-pay p { margin: 0 0 1mm; }
.bl-bank { border-collapse: collapse; font-size: 9.5pt; margin-top: 1mm; } .bl-bank th { font-weight: 400; text-align: left; padding: 0.2mm 6mm 0.2mm 0; white-space: nowrap; } .bl-bank td { text-align: left; font-variant-numeric: tabular-nums; }
.bl-notes { margin: 6mm 0 0; font-size: 9.5pt; line-height: 1.5; } .bl-notes p { margin: 0; }
